// src/App.js - Update the BrowserRouter with future flags
import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ToastProvider } from './context/ToastContext';
import { LoadingProvider } from './context/LoadingContext';
import { RoleProvider, useRole } from './context/RoleContext';
import ErrorBoundary from './components/common/ErrorBoundary';
import HomePage from './pages/HomePage';
import AboutPage from './pages/AboutPage';
import ContactPage from './pages/ContactPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import DashboardPage from './pages/DashboardPage';
import ProfilePage from './pages/ProfilePage';
import RoleBasedNav from './components/common/RoleBasedNav';
import PatientList from './components/doctor/PatientList';
import PrescriptionList from './components/prescriptions/PrescriptionList';
import MasterAdminDashboard from './pages/admin/MasterAdminDashboard';
import RoleManagementPage from './pages/admin/RoleManagementPage';
import UserVerificationPage from './pages/admin/UserVerificationPage';
import './styles/App.css';

// Protected Route component
const ProtectedRoute = ({ children, requiredRole, requiredPermissions = [], requireAll = false }) => {
    const { user, loading } = useAuth();
    const { hasAnyPermission, hasAllPermissions, isRole } = useRole();
    
    if (loading) {
        return <div className="loading-spinner">Loading...</div>;
    }
    
    if (!user) {
        return <Navigate to="/login" />;
    }
    
    // Check if route requires a specific role
    if (requiredRole && !isRole(requiredRole)) {
        // Redirect master admin to admin dashboard, others to regular dashboard
        if (isRole('master_admin')) {
            return <Navigate to="/admin" />;
        }
        return <Navigate to="/dashboard" />;
    }
    
    // Check permissions
    if (requiredPermissions.length > 0) {
        let hasAccess = false;
        
        if (requireAll) {
            hasAccess = hasAllPermissions(requiredPermissions);
        } else {
            hasAccess = hasAnyPermission(requiredPermissions);
        }
        
        if (!hasAccess) {
            return <Navigate to="/dashboard" />;
        }
    }
    
    return children;
};

// Public Route component
const PublicRoute = ({ children }) => {
    const { user, loading } = useAuth();
    const { isRole } = useRole();
    
    if (loading) {
        return <div className="loading-spinner">Loading...</div>;
    }
    
    if (!user) {
        return children;
    }
    
    // Redirect based on role
    if (isRole('master_admin')) {
        return <Navigate to="/admin" />;
    }
    return <Navigate to="/dashboard" />;
};

function AppContent() {
    const { user } = useAuth();
    
    return (
        <div className="app">
            <header className="app-header">
                <h1>🏥 E-Health System</h1>
                {user && user.verification_status === 'pending' && (
                    <div className="verification-banner">
                        ⏳ Your account is pending verification. Some features may be limited.
                    </div>
                )}
            </header>
            
            {/* Role-based navigation - only show when user is logged in */}
            {user && <RoleBasedNav />}
            
            <main className="app-main">
                <Routes>
                    {/* Public Routes */}
                    <Route path="/" element={<HomePage />} />
                    <Route path="/login" element={
                        <PublicRoute>
                            <LoginPage />
                        </PublicRoute>
                    } />
                    <Route path="/register" element={
                        <PublicRoute>
                            <RegisterPage />
                        </PublicRoute>
                    } />
                    <Route path="/contact" element={
                        <ContactPage />} />
                    
                    {/* Master Admin Routes - Must come before generic dashboard */}
                    <Route path="/admin" element={
                        <ProtectedRoute requiredRole="master_admin">
                            <MasterAdminDashboard />
                        </ProtectedRoute>
                    } />
                    <Route path="/admin/roles" element={
                        <ProtectedRoute requiredRole="master_admin">
                            <RoleManagementPage />
                        </ProtectedRoute>
                    } />
                    <Route path="/admin/verifications" element={
                        <ProtectedRoute requiredRole="master_admin">
                            <UserVerificationPage />
                        </ProtectedRoute>
                    } />
                    
                    {/* Protected Routes - Patient & Doctor */}
                    <Route path="/dashboard" element={
                        <ProtectedRoute>
                            <DashboardPage />
                        </ProtectedRoute>
                    } />
                    <Route path="/about" element={
                        <AboutPage />} />
                    <Route path="/profile" element={
                        <ProtectedRoute>
                            <ProfilePage />
                        </ProtectedRoute>
                    } />
                    
                    {/* Doctor-Only Routes */}
                    <Route path="/patients" element={
                        <ProtectedRoute requiredRole="doctor">
                            <PatientList />
                        </ProtectedRoute>
                    } />
                    <Route path="/prescriptions" element={
                        <ProtectedRoute>
                            <PrescriptionList />
                        </ProtectedRoute>
                    } />
                    
                    {/* Fallback Route */}
                    <Route path="*" element={<Navigate to="/" replace />} />
                </Routes>
            </main>
            
            {/* Simple Footer */}
            <footer className="app-footer">
                <div className="footer-content">
                    <p>&copy; 2025 E-Health System. All rights reserved.</p>
                    <p>Secure Electronic Health Records with Fingerprint Authentication</p>
                </div>
            </footer>
        </div>
    );
}

// Wrap the app content
function App() {
    return (
        <ErrorBoundary>
            <Router
                future={{
                    v7_startTransition: true,
                    v7_relativeSplatPath: true,
                }}
            >
                <AuthProvider>
                    <RoleProvider>
                        <ToastProvider>
                            <LoadingProvider>
                                <AppContent />
                            </LoadingProvider>
                        </ToastProvider>
                    </RoleProvider>
                </AuthProvider>
            </Router>
        </ErrorBoundary>
    );
}

export default App;
